   257→    async function loadRecruiterDashboard() {
   258→      try {
   259→        const data = await apiCall('/recruiter/dashboard');
   260→        if (!data) return;
   261→
   262→        // Update TrustScore
   263→        if (data.trust_score) {
   264→          document.getElementById('trustscore-value').textContent = data.trust_score.total_score;
   265→          document.getElementById('trustscore-tier').textContent = data.trust_score.tier_label;
   266→          document.getElementById('trustscore-tier').style.background = data.trust_score.tier_color;
   267→        }
   268→
   269→        // Update stats
   270→        document.getElementById('active-jobs').textContent = data.job_stats?.active_jobs || 0;
   271→        document.getElementById('total-applications').textContent = data.application_stats?.total_applications || 0;
   272→        document.getElementById('new-applications').textContent = data.application_stats?.new_applications || 0;
   273→
   274→        const interviewed = parseInt(data.application_stats?.interviewed) || 0;
   275→        const offered = parseInt(data.application_stats?.offered) || 0;
   276→        const ratio = interviewed > 0 ? ((offered / interviewed) * 100).toFixed(0) + '%' : '-';
   277→        document.getElementById('offer-ratio').textContent = ratio;
   278→
   279→        // Render upcoming interviews
   280→        renderUpcomingInterviews(data.upcoming_interviews || []);
   281→
   282→        // Render recent applications
   283→        renderRecentApplications(data.recent_applications || []);
   284→
   285→      } catch (err) {
